import{_ as o,O as l,H as i,f as s,i as h,b as d,j as r,k as e}from"./chunks/framework.Pt2pSV98.js";const u=JSON.parse('{"title":"学习路线图","description":"循序渐进学习 AI 的完整路径","frontmatter":{"title":"学习路线图","description":"循序渐进学习 AI 的完整路径"},"headers":[],"relativePath":"roadmap/index.md","filePath":"roadmap/index.md"}'),n={name:"roadmap/index.md"};function p(b,t,y,c,m,D){const a=l("DifficultyBadge");return i(),s("div",null,[t[4]||(t[4]=h('<h1 id="🧭-ai-学习路线图" tabindex="-1">🧭 AI 学习路线图 <a class="header-anchor" href="#🧭-ai-学习路线图" aria-label="Permalink to &quot;🧭 AI 学习路线图&quot;">​</a></h1><p>按 <strong>周</strong> 为单位规划，每周聚焦一个主题。你可以按自己的节奏调整，建议顺序如下：</p><hr><h2 id="第-0-周-了解历史-—-ai-发展历程" tabindex="-1">第 0 周：了解历史 — AI 发展历程 <a class="header-anchor" href="#第-0-周-了解历史-—-ai-发展历程" aria-label="Permalink to &quot;第 0 周：了解历史 — AI 发展历程&quot;">​</a></h2><p>在开始学习具体知识之前，先花 5 分钟了解 AI 如何走到今天——这能帮你理解<strong>为什么这些概念重要</strong>。</p><table tabindex="0"><thead><tr><th>时间</th><th>里程碑</th><th>意义</th></tr></thead><tbody><tr><td><strong>1956</strong></td><td>Dartmouth 夏季研讨会</td><td>AI 作为学科正式诞生</td></tr><tr><td><strong>1997</strong></td><td>深蓝 (DeepBlue) 击败卡斯帕罗夫</td><td>AI 首次在智力博弈中战胜人类世界冠军</td></tr><tr><td><strong>2012</strong></td><td>AlexNet 赢得 ImageNet 竞赛</td><td>深度学习时代开启，计算机视觉迎来质变</td></tr><tr><td><strong>2017</strong></td><td>Google 发表《Attention Is All You Need》</td><td>Transformer 架构诞生，为所有大模型奠定基础</td></tr><tr><td><strong>2022</strong></td><td>OpenAI 发布 ChatGPT</td><td>AI 进入大众视野，月活 2 个月破亿</td></tr><tr><td><strong>2024</strong></td><td>GPT-4o / Claude 3 / 多模态爆发</td><td>AI 从纯文本走向多模态，能力全面跃升</td></tr><tr><td><strong>2025</strong></td><td>DeepSeek / Agent 框架成熟</td><td>开源模型逼近闭源、AI 自主执行任务成为现实</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">为什么要先了解历史？</p><p>每一个术语背后都有一段故事。知道了 Transformer 为什么在 2017 年取代 RNN，你就能真正理解它&quot;解决了什么问题&quot;，而不仅仅是背一个定义。</p></div><p>→ <a href="/ai-knowledge/terms/history.html">📜 查看完整 AI 发展历程</a></p><hr><h2 id="第-1-周-打好基础-—-ai-术语" tabindex="-1">第 1 周：打好基础 — AI 术语 <a class="header-anchor" href="#第-1-周-打好基础-—-ai-术语" aria-label="Permalink to &quot;第 1 周：打好基础 — AI 术语&quot;">​</a></h2><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>难度</th></tr></thead><tbody><tr><td>Day 1</td><td>AI / ML / DL 是什么</td><td>🟢</td></tr><tr><td>Day 2</td><td>大语言模型 (LLM) 与 Token</td><td>🟢</td></tr><tr><td>Day 3</td><td>Prompt / 上下文窗口 / 多模态</td><td>🟢</td></tr><tr><td>Day 4</td><td>参数 / 训练 / 推理 / 微调</td><td>🟢</td></tr><tr><td>Day 5</td><td>Transformer 与自注意力</td><td>🟡</td></tr><tr><td>Day 6</td><td>RAG / Embedding / 向量数据库</td><td>🟡</td></tr><tr><td>Day 7</td><td>复习 + 小测验</td><td>—</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">目标</p><p>学完能听懂 AI 领域的日常对话，知道这些概念大致在说什么。</p></div><h2 id="第-2-周-学会对话-—-提示词" tabindex="-1">第 2 周：学会对话 — 提示词 <a class="header-anchor" href="#第-2-周-学会对话-—-提示词" aria-label="Permalink to &quot;第 2 周：学会对话 — 提示词&quot;">​</a></h2><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>难度</th></tr></thead><tbody><tr><td>Day 1</td><td>什么是 Prompt + 清晰指令五原则</td><td>🟢</td></tr><tr><td>Day 2</td><td>角色设定 / Few-Shot / Zero-Shot</td><td>🟢</td></tr><tr><td>Day 3</td><td>思维链 (Chain-of-Thought)</td><td>🟡</td></tr><tr><td>Day 4</td><td>System Prompt 设计</td><td>🟡</td></tr><tr><td>Day 5</td><td>结构化提示词</td><td>🟡</td></tr><tr><td>Day 6</td><td>场景模板实战（写作/编程/分析）</td><td>🟡</td></tr><tr><td>Day 7</td><td>综合练习：优化一个 Prompt 链</td><td>🔴</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">目标</p><p>学会写出高质量的提示词，能稳定地从 AI 获得好结果。</p></div><h2 id="第-3-周-了解武器-—-ai-工具" tabindex="-1">第 3 周：了解武器 — AI 工具 <a class="header-anchor" href="#第-3-周-了解武器-—-ai-工具" aria-label="Permalink to &quot;第 3 周：了解武器 — AI 工具&quot;">​</a></h2><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>难度</th></tr></thead><tbody><tr><td>Day 1</td><td>ChatGPT vs Claude vs DeepSeek</td><td>🟢</td></tr><tr><td>Day 2</td><td>Kimi / Gemini / 其他对话助手</td><td>🟢</td></tr><tr><td>Day 3</td><td>Cursor / Windsurf / Copilot</td><td>🟡</td></tr><tr><td>Day 4</td><td>OpenCode / Cline / Aider</td><td>🟡</td></tr><tr><td>Day 5</td><td>Midjourney / DALL·E / Stable Diffusion</td><td>🟢</td></tr><tr><td>Day 6</td><td>工具组合与工作流</td><td>🟡</td></tr><tr><td>Day 7</td><td>选型总结：什么场景用什么工具</td><td>🔴</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">目标</p><p>了解各个工具的能力边界，能根据场景快速选择合适工具。</p></div><h2 id="第-4-周-动手实践-—-实操" tabindex="-1">第 4 周：动手实践 — 实操 <a class="header-anchor" href="#第-4-周-动手实践-—-实操" aria-label="Permalink to &quot;第 4 周：动手实践 — 实操&quot;">​</a></h2><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>难度</th></tr></thead><tbody><tr><td>Day 1</td><td>用 ChatGPT 辅助编程</td><td>🟢</td></tr><tr><td>Day 2</td><td>用 Cursor 10 分钟搭建网页</td><td>🟢</td></tr><tr><td>Day 3</td><td>用 Claude 分析文档</td><td>🟢</td></tr><tr><td>Day 4</td><td>搭建 RAG 知识库</td><td>🟡</td></tr><tr><td>Day 5</td><td>用 Vercel AI SDK 构建聊天机器人</td><td>🟡</td></tr><tr><td>Day 6</td><td>Prompt 批量生成工作流</td><td>🟡</td></tr><tr><td>Day 7</td><td>综合挑战：用 AI 完成一个完整需求</td><td>🔴</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">目标</p><p>能独立用 AI 工具完成实际工作，把知识转化为生产力。</p></div><h2 id="第-5-周-进阶开发-—-ai-编程" tabindex="-1">第 5 周：进阶开发 — AI 编程 <a class="header-anchor" href="#第-5-周-进阶开发-—-ai-编程" aria-label="Permalink to &quot;第 5 周：进阶开发 — AI 编程&quot;">​</a></h2><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>难度</th></tr></thead><tbody><tr><td>Day 1</td><td>OpenAI API 入门</td><td>🟢</td></tr><tr><td>Day 2</td><td>流式响应 (Streaming)</td><td>🟡</td></tr><tr><td>Day 3</td><td>Tool Calling</td><td>🟡</td></tr><tr><td>Day 4</td><td>结构化输出 (JSON Mode)</td><td>🟡</td></tr><tr><td>Day 5</td><td>Agent 核心概念</td><td>🟡</td></tr><tr><td>Day 6</td><td>构建第一个 Agent</td><td>🔴</td></tr><tr><td>Day 7</td><td>综合项目：用 AI 构建一个实用工具</td><td>🔴</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">目标</p><p>能通过 API 调用 AI 模型，构建简单的 Agent 应用，把 AI 集成到自己的项目里。</p></div><h2 id="第-6-周-工程化落地-—-架构·安全·部署" tabindex="-1">第 6 周：工程化落地 — 架构·安全·部署 <a class="header-anchor" href="#第-6-周-工程化落地-—-架构·安全·部署" aria-label="Permalink to &quot;第 6 周：工程化落地 — 架构·安全·部署&quot;">​</a></h2><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>难度</th></tr></thead><tbody><tr><td>Day 1</td><td>AI 应用架构：缓存策略</td><td>🟡</td></tr><tr><td>Day 2</td><td>AI 应用架构：错误处理与成本控制</td><td>🟡</td></tr><tr><td>Day 3</td><td>模型评估与自动化测试</td><td>🟡</td></tr><tr><td>Day 4</td><td>AI 安全：Prompt 注入防御</td><td>🟡</td></tr><tr><td>Day 5</td><td>本地模型部署：Ollama 入门</td><td>🟢</td></tr><tr><td>Day 6</td><td>综合项目：带缓存的本地 AI 助手</td><td>🔴</td></tr><tr><td>Day 7</td><td>整体回顾与知识体系梳理</td><td>—</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">目标</p><p>能设计可靠的 AI 应用架构，理解安全风险，会部署本地模型，具备把 AI 项目落地的工程能力。</p></div><h2 id="第-7-周-深入拓展-—-多模态·mcp·rag" tabindex="-1">第 7 周：深入拓展 — 多模态·MCP·RAG <a class="header-anchor" href="#第-7-周-深入拓展-—-多模态·mcp·rag" aria-label="Permalink to &quot;第 7 周：深入拓展 — 多模态·MCP·RAG&quot;">​</a></h2><table tabindex="0"><thead><tr><th>天数</th><th>学习内容</th><th>难度</th></tr></thead><tbody><tr><td>Day 1</td><td>多模态编程：Vision API 实战</td><td>🟡</td></tr><tr><td>Day 2</td><td>推理模型：o1 / DeepSeek-R1 使用</td><td>🟡</td></tr><tr><td>Day 3</td><td>MCP 协议：构建自己的 MCP Server</td><td>🔴</td></tr><tr><td>Day 4</td><td>RAG 深度：分块与 Embedding 选型</td><td>🔴</td></tr><tr><td>Day 5</td><td>RAG 深度：Re-ranking 精排</td><td>🔴</td></tr><tr><td>Day 6</td><td>综合项目：带 MCP 的多模态 Agent</td><td>🔴</td></tr><tr><td>Day 7</td><td>自由探索 + 查看学习报告</td><td>—</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">目标</p><p>掌握多模态编程和推理模型的使用，能构建 MCP Server 扩展 Agent 能力，让 RAG 从能用变好用。</p></div><hr><table tabindex="0"><thead><tr><th>模式</th><th>适合谁</th><th>怎么做</th></tr></thead><tbody><tr><td>🧭 <strong>跟着路线走</strong></td><td>零基础 / 系统性学习者</td><td>按周推进，完成前一周再进下一周</td></tr><tr><td>🔍 <strong>自由探索</strong></td><td>有基础 / 目标明确者</td><td>直接跳到感兴趣的模块，按需学习</td></tr><tr><td>⚡ <strong>快速查漏</strong></td><td>有一定经验者</td><td>搜索关键词，只看自己不熟悉的部分</td></tr></tbody></table>',32)),d("p",null,[t[0]||(t[0]=r("难度标识：",-1)),e(a,{level:"beginner"}),t[1]||(t[1]=r(" 无前置要求 · ",-1)),e(a,{level:"intermediate"}),t[2]||(t[2]=r(" 需入门基础 · ",-1)),e(a,{level:"advanced"}),t[3]||(t[3]=r(" 需实践经验",-1))]),t[5]||(t[5]=d("div",{style:{"margin-top":"32px",display:"flex",gap:"12px","flex-wrap":"wrap"}},[d("a",{href:"../terms/",class:"btn"},"开始第 1 周 → 📖 术语"),d("a",{href:"../prompts/",class:"btn btn-alt"},"跳转到第 2 周 → 💬 提示词")],-1))])}const g=o(n,[["render",p]]);export{u as __pageData,g as default};
